// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000000

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* parent;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int value) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->value = value;
    node->parent = NULL;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->numChildren++;
    parent->children = (Node**) realloc(parent->children, parent->numChildren * sizeof(Node*));
    parent->children[parent->numChildren - 1] = child;
    child->parent = parent;
}

// Function to calculate the minimum capacity of the boat
int calculateCapacity(Node* root) {
    int maxDegree = 0;
    // Perform a depth-first search to calculate the maximum degree of the tree
    void dfs(Node* node) {
        int degree = node->numChildren;
        if (degree > maxDegree) {
            maxDegree = degree;
        }
        for (int i = 0; i < node->numChildren; i++) {
            dfs(node->children[i]);
        }
    }
    dfs(root);
    return maxDegree + 1;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node* root = createNode(1);
        Node** nodes = (Node**) malloc(N * sizeof(Node*));
        nodes[0] = root;
        for (int i = 1; i < N; i++) {
            int parentIndex;
            scanf("%d", &parentIndex);
            Node* parentNode = nodes[parentIndex - 1];
            Node* childNode = createNode(i + 1);
            addChild(parentNode, childNode);
            nodes[i] = childNode;
            int capacity = calculateCapacity(root);
            printf("%d ", capacity);
        }
        printf("\n");
    }
    return 0;
}

