// COMPLETE, COMPILABLE Java code
import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int value;
        Node parent;
        ArrayList<Node> children;

        public Node(int value) {
            this.value = value;
            this.parent = null;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node parent, Node child) {
        parent.children.add(child);
        child.parent = parent;
    }

    // Function to calculate the minimum capacity of the boat
    public static int calculateCapacity(Node root) {
        int[] maxDegree = new int[] {0};
        // Perform a depth-first search to calculate the maximum degree of the tree
        dfs(root, maxDegree);
        return maxDegree[0] + 1;
    }

    public static void dfs(Node node, int[] maxDegree) {
        int degree = node.children.size();
        if (degree > maxDegree[0]) {
            maxDegree[0] = degree;
        }
        for (Node child : node.children) {
            dfs(child, maxDegree);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            Node root = new Node(1);
            Node[] nodes = new Node[N];
            nodes[0] = root;
            for (int i = 1; i < N; i++) {
                int parentIndex = scanner.nextInt();
                Node parentNode = nodes[parentIndex - 1];
                Node childNode = new Node(i + 1);
                addChild(parentNode, childNode);
                nodes[i] = childNode;
                int capacity = calculateCapacity(root);
                System.out.print(capacity + " ");
            }
            System.out.println();
        }
    }
}

