    constructor(value) {
        this.value = value;
        this.parent = null;
        this.children = [];
    }
}

// Function to add a child to a node
function addChild(parent, child) {
    parent.children.push(child);
    child.parent = parent;
}

// Function to calculate the minimum capacity of the boat
function calculateCapacity(root) {
    let maxDegree = 0;
    // Perform a depth-first search to calculate the maximum degree of the tree
    function dfs(node) {
        let degree = node.children.length;
        if (degree > maxDegree) {
            maxDegree = degree;
        }
        for (let child of node.children) {
            dfs(child);
        }
    }
    dfs(root);
    return maxDegree + 1;
}

